                          <p className="text-sm text-gray-600">Receive push notifications in browser</p>
                        </div>
                      </div>
                      <button
                        onClick={() => setPreferences({
                          ...preferences, 
                          notifications: {...preferences.notifications, push: !preferences.notifications.push}
