                      <div className="flex items-center">
                        <Smartphone className="h-5 w-5 text-gray-400 mr-3" />
                        <div>
                          <h4 className="text-sm font-medium text-gray-900">SMS Notifications</h4>
                          <p className="text-sm text-gray-600">Receive notifications via SMS</p>
                        </div>
                      </div>
                      <button
                        onClick={() => setPreferences({
                          ...preferences, 
                          notifications: {...preferences.notifications, sms: !preferences.notifications.sms}
                        })}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                          preferences.notifications.sms ? 'bg-primary-600' : 'bg-gray-200'
                        }`}
                      >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                          preferences.notifications.sms ? 'translate-x-6' : 'translate-x-1'
                        }`} />
                      </button>
                    </div>
                  </div>
                </div>

                <button
                  onClick={handlePreferencesUpdate}
                  disabled={loading}
                  className="btn-primary w-full"
                >
                  {loading ? (
                    <div className="spinner w-4 h-4 mr-2"></div>
                  ) : (
                    <Settings className="h-4 w-4 mr-2" />
                  )}
                  Update Preferences
                </button>
              </div>
            )}

            {activeTab === 'activity' && (
              <div className="space-y-6">
                <div className="card">
                  <div className="card-header">
                    <h3 className="text-lg font-medium text-gray-900">Recent Activity</h3>
                    <p className="text-sm text-gray-600">Your recent account activity</p>
                  </div>
                  <div className="card-body">
                    <div className="space-y-4">
                      {activityData.length > 0 ? (
                        activityData.map((activity, index) => (
                          <div key={index} className="flex items-center p-4 border border-gray-200 rounded-lg">
                            <div className="p-2 bg-blue-100 rounded-lg">
                              <Activity className="h-5 w-5 text-blue-600" />
                            </div>
                            <div className="ml-4 flex-1">
                              <p className="text-sm font-medium text-gray-900">{activity.action}</p>
                              <p className="text-sm text-gray-600">{activity.description}</p>
                              <p className="text-xs text-gray-500">{new Date(activity.timestamp).toLocaleString()}</p>
                            </div>
                            <div className="text-xs text-gray-500">
                              {activity.ip && `IP: ${activity.ip}`}
                            </div>
                          </div>
                        ))
                      ) : (
                        <div className="text-center py-8">
                          <Activity className="h-12 w-12 text-gray-400 mx-auto mb-4" />
                          <p className="text-gray-600">No recent activity</p>
                        </div>
                      )}
                    </div>
                  </div>
                </div>
              </div>
            )}

            {activeTab === 'data' && (
              <div className="space-y-6">
                <div className="card">
                  <div className="card-header">
                    <h3 className="text-lg font-medium text-gray-900">Data Export</h3>
                    <p className="text-sm text-gray-600">Download your data</p>
                  </div>
                  <div className="card-body">
                    <div className="flex items-center justify-between p-4 border border-gray-200 rounded-lg">
                      <div className="flex items-center">
                        <div className="p-2 bg-green-100 rounded-lg">
                          <Download className="h-6 w-6 text-green-600" />
                        </div>
                        <div className="ml-4">
                          <h4 className="text-sm font-medium text-gray-900">Export Your Data</h4>
                          <p className="text-sm text-gray-600">Download all your surveys, responses, and account data</p>
                        </div>
                      </div>
                      <button
                        onClick={() => setShowExportModal(true)}
                        className="btn-secondary"
                      >
                        <Download className="h-4 w-4 mr-2" />
                        Export Data
                      </button>
                    </div>
                  </div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <h3 className="text-lg font-medium text-gray-900">Privacy Settings</h3>
                    <p className="text-sm text-gray-600">Control your privacy and data sharing</p>
                  </div>
                  <div className="card-body space-y-4">
                    <div>
                      <label className="block text-sm font-medium text-gray-700">Profile Visibility</label>
                      <select
                        value={preferences.privacy.profileVisibility}
                        onChange={(e) => setPreferences({
                          ...preferences, 
                          privacy: {...preferences.privacy, profileVisibility: e.target.value}
                        })}
                        className="input mt-1"
                      >
                        <option value="public">Public</option>
                        <option value="private">Private</option>
                        <option value="friends">Friends Only</option>
                      </select>
                    </div>

                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="text-sm font-medium text-gray-900">Show Email Address</h4>
                        <p className="text-sm text-gray-600">Allow others to see your email address</p>
                      </div>
                      <button
                        onClick={() => setPreferences({
                          ...preferences, 
                          privacy: {...preferences.privacy, showEmail: !preferences.privacy.showEmail}
                        })}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                          preferences.privacy.showEmail ? 'bg-primary-600' : 'bg-gray-200'
                        }`}
                      >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                          preferences.privacy.showEmail ? 'translate-x-6' : 'translate-x-1'
                        }`} />
                      </button>
                    </div>

                    <div className="flex items-center justify-between">
                      <div>
                        <h4 className="text-sm font-medium text-gray-900">Show Activity</h4>
                        <p className="text-sm text-gray-600">Allow others to see your activity</p>
                      </div>
                      <button
                        onClick={() => setPreferences({
                          ...preferences, 
                          privacy: {...preferences.privacy, showActivity: !preferences.privacy.showActivity}
                        })}
                        className={`relative inline-flex h-6 w-11 items-center rounded-full transition-colors ${
                          preferences.privacy.showActivity ? 'bg-primary-600' : 'bg-gray-200'
                        }`}
                      >
                        <span className={`inline-block h-4 w-4 transform rounded-full bg-white transition-transform ${
                          preferences.privacy.showActivity ? 'translate-x-6' : 'translate-x-1'
                        }`} />
                      </button>
                    </div>
                  </div>
                </div>

                <div className="card">
                  <div className="card-header">
                    <h3 className="text-lg font-medium text-gray-900">Danger Zone</h3>
                    <p className="text-sm text-gray-600">Irreversible actions</p>
                  </div>
                  <div className="card-body">
                    <div className="flex items-center justify-between p-4 border border-red-200 rounded-lg bg-red-50">
                      <div className="flex items-center">
                        <div className="p-2 bg-red-100 rounded-lg">
                          <Trash2 className="h-6 w-6 text-red-600" />
                        </div>
                        <div className="ml-4">
                          <h4 className="text-sm font-medium text-red-900">Delete Account</h4>
                          <p className="text-sm text-red-700">Permanently delete your account and all data</p>
                        </div>
                      </div>
                      <button
                        onClick={() => setShowDeleteModal(true)}
                        className="btn-danger"
                      >
                        <Trash2 className="h-4 w-4 mr-2" />
                        Delete Account
                      </button>
                    </div>
                  </div>
                </div>
              </div>
            )}
          </div>
        </div>
      </div>

      {/* Export Modal */}
      {showExportModal && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-medium text-gray-900">Export Data</h3>
              <button
                onClick={() => setShowExportModal(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <X className="h-6 w-6" />
              </button>
            </div>
            <p className="text-sm text-gray-600 mb-4">
              This will download all your surveys, responses, and account data in JSON format.
            </p>
            <div className="flex space-x-3">
              <button
                onClick={() => setShowExportModal(false)}
                className="btn-secondary flex-1"
              >
                Cancel
              </button>
              <button
                onClick={exportUserData}
                disabled={loading}
                className="btn-primary flex-1"
              >
                {loading ? (
                  <div className="spinner w-4 h-4 mr-2"></div>
                ) : (
                  <Download className="h-4 w-4 mr-2" />
                )}
                Export
              </button>
            </div>
          </div>
        </div>
      )}

      {/* Delete Account Modal */}
      {showDeleteModal && (
        <div className="fixed inset-0 bg-gray-600 bg-opacity-50 flex items-center justify-center z-50">
          <div className="bg-white rounded-lg p-6 max-w-md w-full mx-4">
            <div className="flex items-center justify-between mb-4">
              <h3 className="text-lg font-medium text-red-900">Delete Account</h3>
              <button
                onClick={() => setShowDeleteModal(false)}
                className="text-gray-400 hover:text-gray-600"
              >
                <X className="h-6 w-6" />
              </button>
            </div>
            <div className="flex items-center mb-4">
              <AlertTriangle className="h-6 w-6 text-red-600 mr-3" />
              <p className="text-sm text-red-700">
                This action cannot be undone. All your surveys, responses, and account data will be permanently deleted.
              </p>
            </div>
            <div className="flex space-x-3">
              <button
                onClick={() => setShowDeleteModal(false)}
                className="btn-secondary flex-1"
              >
                Cancel
              </button>
              <button
                onClick={deleteAccount}
                disabled={loading}
                className="btn-danger flex-1"
              >
                {loading ? (
                  <div className="spinner w-4 h-4 mr-2"></div>
                ) : (
                  <Trash2 className="h-4 w-4 mr-2" />
                )}
                Delete Account
              </button>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

export default Profile;
